import{_ as t,o as a,c as n,a4 as i}from"./chunks/framework.CtnSHCpE.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/zopen-alt.md","filePath":"reference/zopen-alt.md","lastUpdated":1777277712000}'),o={name:"reference/zopen-alt.md"};function r(l,e,s,p,m,f){return a(),n("div",null,[...e[0]||(e[0]=[i('<div class="man-page-content"><div class="header-with-back"><div class="back-link"><a href="./zopen-reference">← Back</a></div></div><h1 align="center">ZOPEN-ALT</h1><h2>NAME <a name="NAME"></a></h2><p style="margin-left:11%;margin-top:1em;">zopen-alt − manual page for zopen-alt 0.8.4</p><h2>SYNOPSIS <a name="SYNOPSIS"></a></h2><p style="margin-left:11%;margin-top:1em;"><b>zopen-alt</b> [<i>OPTION</i>] [<i>PACKAGE</i>] [<i>PARAMETERS</i>]...</p><h2>DESCRIPTION <a name="DESCRIPTION"></a></h2><p style="margin-left:11%;margin-top:1em;">zopen−alt is a utility for zopen community to switch package versions for currently installed packages.</p><h2>OPTIONS <a name="OPTIONS"></a></h2><p style="margin-left:11%;margin-top:1em;"><b>−h</b>, <b>−−help</b>, −?</p><p style="margin-left:22%;">display this help and exit.</p><p style="margin-left:11%;"><b>−−select</b> [PACKAGE]</p><p style="margin-left:22%;">select the active version for PACKAGE from a list.</p><p style="margin-left:11%;"><b>−s</b>, <b>−−set</b> [PACKAGE] [VERSION]</p><p style="margin-left:22%;">set the active version for PACKAGE to VERSION.</p><p style="margin-left:11%;"><b>−v</b>, <b>−−verbose</b></p><p style="margin-left:22%;">run in verbose mode.</p><p style="margin-left:11%;"><b>−−version</b></p><p style="margin-left:22%;">print version</p><h2>EXAMPLES <a name="EXAMPLES"></a></h2><p style="margin-left:11%;margin-top:1em;">zopen alt foo</p><p style="margin-left:22%;">list the available alternatives for package ’foo’</p><p style="margin-left:11%;">zopen alt −−select foo</p><p style="margin-left:22%;">list the available alternatives for package ’foo’ and allow the user to select an alternative version</p><p style="margin-left:11%;">zopen alt −−set foo foo−1.2.3.19700101_012345.zos</p><p style="margin-left:22%;">set the active version of package ’foo’ to version foo−1.2.3.19700101_012345.zos if available</p><h2>AUTHOR <a name="AUTHOR"></a></h2><p style="margin-left:11%;margin-top:1em;">Written by contributors to the zopen community. &lt;https://github.com/zopencommunity/meta/graphs/contributors&gt;</p><h2>REPORTING BUGS <a name="REPORTING BUGS"></a></h2><p style="margin-left:11%;margin-top:1em;">Report bugs at https://github.com/zopencommunity/meta/issues</p><p style="margin-left:11%;margin-top:1em;">This is free software: you are free to change and redistribute it under the terms of the Apache License, Version 2.0. &lt;https://www.apache.org/licenses/LICENSE−2.0.html&gt; There is NO WARRANTY, to the extent permitted by law.</p></div>',1)])])}const g=t(o,[["render",r]]);export{h as __pageData,g as default};
